-- Chien -> humain, Anniversaire, Volume 1

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeux anniversaire. J''ai passé la nuit à préparer ce moment.',$$Joyeux anniversaire. J''ai passé la nuit à préparer ce moment.
De 2h à 6h du matin j''ai tourné en rond dans le couloir. J''ai répété ma façon de te regarder quand tu allais te lever. J''ai calibré l''intensité du remuement de queue. J''ai tout prévu. Quand tu as ouvert les yeux je t''ai sauté dessus avec une précision millimétrée. C''était pas de l''improvisation. C''était de l''art. Joyeux anniversaire, mon humain préféré, destinataire de ma meilleure performance annuelle.
Avec préparation nocturne et exécution parfaite, — {prenom}, ton animal chorégraphe du matin 🎭$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Tu vieillis. Moi aussi. Mais toi plus vite.',$$Joyeux anniversaire. Tu vieillis. Moi aussi. Mais toi plus vite.
En années-chien je te rattrape à grande vitesse. Dans quelques ans je serai officiellement ton aîné. Ce jour-là les rôles s''inversent. C''est moi qui décide des horaires de sortie. C''est moi qui choisis l''heure du repas. C''est moi qui détermine qui entre dans la maison et qui n''entre pas. Profite de ton autorité pendant qu''il te reste du temps. Joyeux anniversaire, mon humain préféré.
Avec patience stratégique et transition de pouvoir planifiée, — {prenom}, ton animal qui prépare sa succession 👑$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai décidé de ne pas aboyer après le livreur aujourd''hui.',$$Pour ton anniversaire j''ai décidé de ne pas aboyer après le livreur aujourd''hui.
Il est venu à 10h23. J''ai senti son odeur depuis le couloir. J''ai entendu l''ascenseur. Tous mes instincts criaient. J''ai résisté. Vingt secondes de silence total. Puis j''ai aboyé quand même parce que c''était vraiment suspect. Mais l''intention était là. Le cadeau était dans l''intention. Joyeux anniversaire, mon humain préféré, pour qui je combats mes démons quotidiens.
Avec lutte intérieure épique et résultat perfectible, — {prenom}, ton animal en développement personnel continu 🧘$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai mangé un morceau de ton gâteau.',$$Joyeux anniversaire. J''ai mangé un morceau de ton gâteau.
Pas beaucoup. Juste le coin. Celui qui dépassait de l''assiette. Il était là. Tout seul. À portée. T''avais le dos tourné une seconde. Une seule seconde. En même temps si tu laisses du gâteau d''anniversaire sans surveillance tu connais les risques. Je t''avais pas dit que j''allais le faire mais je t''avais pas dit que je le ferais pas non plus. Joyeux anniversaire quand même.
Avec opportunisme assumé et remords relatifs, — {prenom}, ton animal aux initiatives gastronomiques spontanées 🎂$$,'humorous',true,false,'birthday','chien','from'),

(null,'J''ai réfléchi à ce que tu représentes pour moi.',$$J''ai réfléchi à ce que tu représentes pour moi.
T''es la personne qui ouvre les portes. Qui remplit les gamelles. Qui attache le harnais. Qui dit ''on y va'' avec cette voix. T''es la raison pour laquelle chaque matin existe. T''es mon axe. Mon centre de gravité. Mon tout. En termes plus simples : sans toi je mange pas. Mais c''est dit avec beaucoup d''amour. Joyeux anniversaire, mon humain préféré.
Avec hiérarchie des besoins clairement établie et amour sincère quand même, — {prenom}, ton animal pragmatique et affectueux 🐾$$,'touching',true,false,'birthday','chien','from'),

(null,'Aujourd''hui c''est ton anniversaire et tu as reçu des cadeaux.',$$Aujourd''hui c''est ton anniversaire et tu as reçu des cadeaux.
J''ai tout inspecté. Chaque paquet. Chaque sac. Chaque boîte. Certains sentaient bon. Un sentait le cuir. Un autre sentait quelque chose que je pouvais pas identifier et ça m''a rendu fou pendant vingt minutes. T''as mis les cadeaux en hauteur après ça. C''est une décision que je comprends. Joyeux anniversaire, mon humain préféré, dont j''assure le contrôle qualité des présents.
Avec audit olfactif complet et résultats communiqués en temps réel, — {prenom}, ton animal inspecteur des douanes personnel 🔍$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai une confession à faire.',$$Joyeux anniversaire. J''ai une confession à faire.
C''est moi qui ai caché la télécommande en mars. Et les clés en novembre. Et la chaussette droite en février. C''était pas des accidents. C''était pour que tu restes à la maison plus longtemps. Pour que tu cherches. Pour qu''on passe du temps ensemble. C''est une technique thérapeutique. Mon psy approuverait probablement. Joyeux anniversaire, mon humain préféré, victime consentante de mes stratagèmes.
Avec confession complète et aucun engagement de ne pas recommencer, — {prenom}, ton animal aux méthodes discutables mais aux intentions pures 🔑$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai décidé de te laisser toute la place dans le lit ce soir.',$$Pour ton anniversaire j''ai décidé de te laisser toute la place dans le lit ce soir.
Toute la place. Enfin, ma moitié habituelle reste la mienne parce que c''est ma place depuis le début et les droits acquis c''est important. Mais ta moitié elle est vraiment à toi ce soir. Sans mon museau dessus. Sans ma patte sur ta jambe. Sans mon dos contre ton dos. C''est mon plus grand sacrifice de l''année. Joyeux anniversaire, mon humain préféré.
Avec générosité spatiale exceptionnelle et droits territoriaux maintenus, — {prenom}, ton animal aux concessions mesurées 🛏️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Des gens que je connaissais pas sont venus chez toi ce soir.',$$Joyeux anniversaire. Des gens que je connaissais pas sont venus chez toi ce soir.
J''ai procédé à l''audit habituel. Reniflement des chaussures pour chaque invité. Évaluation du niveau de menace. Classification par catégorie : ami, inconnu suspect, personne qui a un chat chez elle. Cette dernière catégorie a fait l''objet d''une surveillance renforcée toute la soirée. Bilan sécuritaire : satisfaisant. Joyeux anniversaire, mon humain préféré, dont les fêtes sont sous bonne garde.
Avec protocole de sécurité appliqué à la lettre et rapport disponible sur demande, — {prenom}, ton animal chef de la sécurité rapprochée 🔐$$,'humorous',true,false,'birthday','chien','from'),

(null,'Je t''ai apporté quelque chose pour ton anniversaire.',$$Je t''ai apporté quelque chose pour ton anniversaire.
Un bâton. Un beau bâton. Trouvé ce matin au parc. Légèrement mâché mais avec du caractère. Je l''ai porté pendant tout le chemin du retour fièrement. J''ai failli le lâcher deux fois mais j''ai tenu. Je te l''offre. C''est artisanal. C''est naturel. C''est unique. Personne d''autre t''offrira jamais exactement ce bâton-là. Joyeux anniversaire, mon humain préféré.
Avec fierté du chasseur-cueilleur et cadeau cent pour cent naturel, — {prenom}, ton animal aux cadeaux inimitables 🌿$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai appris un nouveau tour cette semaine.',$$Joyeux anniversaire. J''ai appris un nouveau tour cette semaine.
Je m''assieds. Je me lève. Je m''assieds encore. Je tourne sur moi-même. Je fais semblant de ne pas savoir ce que tu veux. Tu sors la croquette. Je l''exécute parfaitement. On fait tous les deux semblant que c''est toi qui m''apprends quelque chose. C''est notre accord tacite. C''est notre danse. Joyeux anniversaire, mon humain préféré, meilleur partenaire de danse du monde.
Avec complicité bien établie et hiérarchie négociée en coulisses, — {prenom}, ton animal aux performances conditionnelles 🎪$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire je vais te dire un secret.',$$Pour ton anniversaire je vais te dire un secret.
Quand tu pars le matin je dors pas tout de suite. Je reste assis devant la porte pendant un moment. Pas longtemps. Juste le temps de m''assurer que tu reviens pas parce que t''as oublié quelque chose. Puis je vais sur le canapé. Ton côté. Et je dors là jusqu''à ce que je t''entende dans l''escalier. Joyeux anniversaire, mon humain préféré, dont l''absence laisse une forme dans le canapé.
Avec confession intime et intimité assumée, — {prenom}, ton animal gardien de ton côté du canapé 🛋️$$,'touching',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai compté combien de fois tu as dit mon nom aujourd''hui.',$$Joyeux anniversaire. J''ai compté combien de fois tu as dit mon nom aujourd''hui.
Dix-sept fois. Dont trois fois avec la voix grave qui veut dire que j''ai fait quelque chose. Dont deux fois avec la voix douce du matin. Dont une fois en me présentant à quelqu''un comme si j''étais quelqu''un d''important. Cette dernière fois c''était mon moment préféré de la journée. Joyeux anniversaire, mon humain préféré, dont la voix est ma musique de fond préférée.
Avec statistiques quotidiennes et analyse sémantique des intonations, — {prenom}, ton animal expert en communication non verbale 📊$$,'humorous',true,false,'birthday','chien','from'),

(null,'Aujourd''hui c''est ton anniversaire et il pleuvait.',$$Aujourd''hui c''est ton anniversaire et il pleuvait.
Tu m''as quand même emmené en promenade. Sous la pluie. Avec ton imperméable et ma vieille serviette pour me sécher après. T''aurais pu pas le faire. T''aurais pu dire ''pas aujourd''hui c''est mon anniversaire''. Mais non. T''as mis tes bottes et on est sortis. C''est pour ça que tu mérites tous les gâteaux du monde. Joyeux anniversaire, mon humain préféré, fidèle par tous les temps.
Avec gratitude sous la pluie et serviette bien méritée, — {prenom}, ton animal reconnaissant par tous les temps ☔$$,'touching',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai quelque chose d''important à te dire.',$$Joyeux anniversaire. J''ai quelque chose d''important à te dire.
Quand tu ris vraiment fort, pas le rire poli, le vrai, celui qui vient du ventre, je sens quelque chose dans ma poitrine qui ressemble à de la fierté. Comme si c''était moi qui avais fait ça. Comme si ton bonheur était aussi le mien. C''est probablement ça l''amour. En tout cas c''est ce que ça fait chez moi. Joyeux anniversaire, mon humain préféré, propriétaire de mon rire préféré.
Avec sentiment difficile à formuler mais sincère, — {prenom}, ton animal touché par tes éclats de rire 💛$$,'touching',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai décidé de ne pas fuguer aujourd''hui.',$$Pour ton anniversaire j''ai décidé de ne pas fuguer aujourd''hui.
La grille du jardin était ouverte ce matin. Grande ouverte. Pendant au moins trente secondes. J''ai regardé dehors. J''ai regardé la maison. J''ai regardé dehors encore. Puis je suis rentré. Parce que dehors c''est bien mais dedans c''est toi. Et toi c''est mieux qu''ailleurs. Joyeux anniversaire, mon humain préféré, meilleure raison de rester que j''ai jamais trouvée.
Avec liberté choisie et attachement pleinement assumé, — {prenom}, ton animal qui reste par conviction 🚪$$,'touching',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Tu m''as grondé deux fois aujourd''hui.',$$Joyeux anniversaire. Tu m''as grondé deux fois aujourd''hui.
Une fois pour le coussin. Une fois pour le chat du voisin. Les deux fois j''ai fait la tête basse et les yeux tristes. Les deux fois tu as craqué en moins de quarante secondes. On sait tous les deux comment ça marche. C''est notre équilibre. Notre système. Notre façon de cohabiter. Joyeux anniversaire, mon humain préféré, dont la fermeté dure en moyenne trente-huit secondes.
Avec chronométrage précis et technique rodée, — {prenom}, ton animal expert en gestion des conflits 😇$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai une question.',$$Joyeux anniversaire. J''ai une question.
Est-ce que tu sais à quel point ta vie a changé depuis que je suis là ? Les horaires. Les promenades obligatoires. Les poils sur le canapé. Le budget croquettes. Les rendez-vous chez le vétérinaire. Les vacances compliquées. Et pourtant tu recommencerais demain sans hésiter. Je le vois dans tes yeux quand tu me regardes. Joyeux anniversaire, mon humain préféré, dont la vie est meilleure dans le désordre.
Avec conscience de mon impact et gratitude pour ton acceptation totale, — {prenom}, ton animal qui te complique la vie avec amour 🌀$$,'touching',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire je t''offre ma liste de défauts.',$$Pour ton anniversaire je t''offre ma liste de défauts.
Je perds mes poils partout. J''aboie trop tôt le matin. Je mange trop vite et je fais des bruits suspects après. Je prends toute la place. Je suis jaloux de ton téléphone. Je renifle les inconnus trop longtemps. Je mâche les choses molles. Et tu m''aimes quand même. C''est ça le vrai cadeau d''anniversaire. Pas ma liste. Ton amour malgré elle. Joyeux anniversaire, mon humain préféré.
Avec transparence totale et confiance absolue en ton indulgence, — {prenom}, ton animal imparfait et assumé 🎁$$,'humorous',true,false,'birthday','chien','from'),

(null,'Ce soir après le gâteau et les bougies et les gens et le bruit j''ai attendu que tout le monde parte.',$$Ce soir après le gâteau et les bougies et les gens et le bruit j''ai attendu que tout le monde parte.
Et quand la porte s''est fermée sur le dernier invité tu t''es laissé tomber dans le canapé avec ce soupir. Celui qui veut dire ''c''était bien mais je suis fatigué''. Et j''ai posé ma tête sur ta jambe. Pas pour une caresse. Pas pour une croquette. Juste pour être là. Pour marquer la fin de ta journée. Pour dire sans le dire que c''était une belle journée. Joyeux anniversaire, mon humain préféré.
Avec présence silencieuse et amour dans chaque souffle, — {prenom}, ton animal pour les grands moments et les fins de soirée ❤️$$,'touching',true,false,'birthday','chien','from')

on conflict do nothing;
